import os
import base64
import asyncio
from datetime import datetime, timezone

from telethon import TelegramClient
from telethon.sessions import StringSession

params = _input.first().json
channel = params["channel"]
since_id = int(params.get("sinceMessageId") or 0)
limit = int(params.get("limit") or 50)
limit = max(1, min(limit, 100))
date_from = params.get("dateFrom")
date_to = params.get("dateTo")
max_bytes = int(os.environ.get("MAX_FILE_MB", "50")) * 1024 * 1024

def parse_dt(v):
    if not v:
        return None
    d = datetime.fromisoformat(str(v).replace("Z", "+00:00"))
    if d.tzinfo is None:
        d = d.replace(tzinfo=timezone.utc)
    return d

df = parse_dt(date_from)
dt2 = parse_dt(date_to)

def media_meta(msg):
    if not msg.media:
        return None
    f = msg.file
    size = getattr(f, "size", None) if f else None
    ext = (getattr(f, "ext", None) if f else None) or ""
    name = (getattr(f, "name", None) if f else None)
    if not name:
        name = (str(msg.id) + ext) if ext else (str(msg.id) + ".bin")
    mime = (getattr(f, "mime_type", None) if f else None) or "application/octet-stream"
    if msg.photo:
        mtype = "photo"
        if name.endswith(".bin"):
            name = str(msg.id) + ".jpg"
        if mime == "application/octet-stream":
            mime = "image/jpeg"
    elif msg.video:
        mtype = "video"
    elif msg.voice:
        mtype = "voice"
    elif msg.audio:
        mtype = "audio"
    elif msg.document:
        mtype = "document"
    else:
        mtype = "other"
    return {"mediaType": mtype, "fileName": name, "mimeType": mime, "size": size}

async def main():
    client = TelegramClient(
        StringSession(os.environ["TELEGRAM_SESSION"]),
        int(os.environ["TELEGRAM_API_ID"]),
        os.environ["TELEGRAM_API_HASH"],
    )
    await client.connect()
    out = []
    try:
        if not await client.is_user_authorized():
            raise Exception("Telegram session not authorized - regenerate the StringSession via the login script.")
        entity = await client.get_entity(channel)
        async for msg in client.iter_messages(entity, limit=limit, min_id=since_id):
            mdate = msg.date
            if df and mdate < df:
                continue
            if dt2 and mdate > dt2:
                continue
            mi = media_meta(msg)
            grouped = getattr(msg, "grouped_id", None)
            j = {
                "messageId": msg.id,
                "channel": str(channel),
                "date": mdate.isoformat(),
                "text": msg.message or "",
                "hasMedia": mi is not None,
                "mediaType": mi["mediaType"] if mi else "none",
                "groupedId": str(grouped) if grouped else None,
            }
            item = {"json": j}
            if mi:
                size = mi["size"] or 0
                if size and size > max_bytes:
                    j["attachmentSkipped"] = True
                    j["fileName"] = mi["fileName"]
                    j["mimeType"] = mi["mimeType"]
                    j["fileSize"] = size
                else:
                    try:
                        data = await client.download_media(msg, file=bytes)
                        if data is None:
                            j["attachmentSkipped"] = True
                        else:
                            item["binary"] = {
                                "attachment": {
                                    "data": base64.b64encode(data).decode("ascii"),
                                    "fileName": mi["fileName"],
                                    "mimeType": mi["mimeType"],
                                }
                            }
                            j["fileName"] = mi["fileName"]
                            j["mimeType"] = mi["mimeType"]
                            j["fileSize"] = size or len(data)
                    except Exception as e:
                        j["attachmentSkipped"] = True
                        j["attachmentError"] = str(e)
            out.append(item)
    finally:
        await client.disconnect()
    return out

return asyncio.run(main())
